"""
install_schedule_screen.py
Run from C:\\vantro-mobile:    python install_schedule_screen.py

Writes the new installer Schedule screen at app/(installer)/schedule.tsx.

Note: this screen will navigate to "/schedule-request" which doesn't exist
yet. That's Phase 2. The Request button will fail until Phase 2 ships.
The rest of the screen (working hours, balance, time-off list) works now.

Idempotent. Safe to re-run.
"""
import base64, os, sys

CONTENT_B64 = ""

TARGET = os.path.join("app", "(installer)", "schedule.tsx")


def main():
    cwd = os.getcwd()
    if not cwd.lower().endswith("vantro-mobile"):
        print(f"WARNING: cwd is {cwd}")
        print("Run from C:\\vantro-mobile. Continue? (y/n)")
        if input().strip().lower() != "y":
            sys.exit(1)

    full = os.path.join(cwd, TARGET)
    os.makedirs(os.path.dirname(full), exist_ok=True)

    contents = base64.b64decode(CONTENT_B64).decode("utf-8")
    with open(full, "w", encoding="utf-8", newline="\n") as f:
        f.write(contents)
    print(f"  wrote: {TARGET}  ({len(contents)} bytes)")
    print()
    print("Done.")
    print()
    print("Test with:  npx expo start")
    print("Then navigate to /schedule from anywhere in the app.")


if __name__ == "__main__":
    main()
